with open("src/adaptive_routing/config.py", "r") as f:
    content = f.read()

def replace_block(content, prefix, item):
    model = item["model"]
    temp = item["temp"]
    max_tokens = item["max_tokens"]
    use_system = "True" if item["use_system"] else "False"
    reasoning = "True" if item["reasoning"] else "False"
    reasoning_effort = item["reasoning_effort"]
    instructions = item["instructions"]
    
    # We will use triple quotes for instructions to avoid backslash escaping issues
    instructions_str = '"""' + instructions.replace('"""', '\\"\\"\\"') + '"""'
    
    # We want to replace the whole block of _PREFIX_* = ...
    # From _PREFIX_MODEL down to the end of _PREFIX_INSTRUCTIONS = ... or _PREFIX_REASONING_EFFORT if instructions doesn't exist
    if prefix == "ROUTER":
        # Router has instructions down at line 161. Let's do it carefully.
        # Replace the first part
        pattern1 = re.compile(r'    _ROUTER_MODEL = .*?_ROUTER_REASONING_EFFORT = [^\n]*\n', re.DOTALL)
        repl1 = (f'    _ROUTER_MODEL = os.getenv("ROUTER_MODEL", "{model}")\n'
                 f'    _ROUTER_TEMP = float(os.getenv("ROUTER_TEMP", "{temp}"))\n'
                 f'    _ROUTER_MAX_TOKENS = int(os.getenv("ROUTER_MAX_TOKENS", "{max_tokens}"))\n'
                 f'    _ROUTER_USE_SYSTEM = os.getenv("ROUTER_USE_SYSTEM", "{use_system}").lower() == "true"\n'
                 f'    _ROUTER_REASONING = os.getenv("ROUTER_REASONING", "{reasoning}").lower() == "true"\n'
                 f'    _ROUTER_REASONING_EFFORT = os.getenv("ROUTER_REASONING_EFFORT", "{reasoning_effort}")\n')
        content = pattern1.sub(repl1, content)
        
        # Replace instructions
        pattern2 = re.compile(r'    _ROUTER_INSTRUCTIONS = os\.getenv\("ROUTER_INSTRUCTIONS", \(.*?\)\)\n', re.DOTALL)
        repl2 = f'    _ROUTER_INSTRUCTIONS = os.getenv("ROUTER_INSTRUCTIONS", {instructions_str})\n'
        content = pattern2.sub(repl2, content)
    else:
        # Standard block
        pattern = re.compile(rf'    _{prefix}_MODEL = .*?_{prefix}_INSTRUCTIONS = os\.getenv\("{prefix}_INSTRUCTIONS", \((.*?)\)\)\n', re.DOTALL)
        repl = (f'    _{prefix}_MODEL = os.getenv("{prefix}_MODEL", "{model}")\n'
                f'    _{prefix}_TEMP = float(os.getenv("{prefix}_TEMP", "{temp}"))\n'
                f'    _{prefix}_MAX_TOKENS = int(os.getenv("{prefix}_MAX_TOKENS", "{max_tokens}"))\n'
                f'    _{prefix}_USE_SYSTEM = os.getenv("{prefix}_USE_SYSTEM", "{use_system}").lower() == "true"\n'
                f'    _{prefix}_REASONING = os.getenv("{prefix}_REASONING", "{reasoning}").lower() == "true"\n'
                f'    _{prefix}_REASONING_EFFORT = os.getenv("{prefix}_REASONING_EFFORT", "{reasoning_effort}")\n'
                f'    _{prefix}_INSTRUCTIONS = os.getenv("{prefix}_INSTRUCTIONS", {instructions_str})\n')
        content = pattern.sub(repl, content)
        
    return content

content = replace_block(content, "TRIAGE", config["triage"])
content = replace_block(content, "ROUTER", config["router"])
content = replace_block(content, "GENERAL", config["general"])
content = replace_block(content, "REASONING", config["reasoning"])
content = replace_block(content, "CASUAL", config["casual"])

with open("src/adaptive_routing/config.py", "w") as f:
    f.write(content)

